@namespace Lumeo
@inject IComponentInteropService Interop

@* <gotcha>Data-bound mode (the Items parameter) still requires <SelectTrigger /> and <SelectContent /> children — a bare <Select Items="..." /> with no children shows only an empty field. Map items with ItemValue/ItemText; items are typed as object, so the data-bound Select is not generic.</gotcha> *@

@{
    var navItems = NavItems;
    var focusedItemId = _focusedIndex >= 0 && _focusedIndex < navItems.Count ? navItems[_focusedIndex].Id : null;
    var focusedItemValue = _focusedIndex >= 0 && _focusedIndex < navItems.Count ? navItems[_focusedIndex].Value : null;
    var context = new SelectContext(Value, Open, Searchable, SearchText, Multiple, Values, IsLoading, Disabled, Clearable, Creatable, MaxDisplayTags,
        EventCallback.Factory.Create<string>(this, OnValueSelected),
        EventCallback.Factory.Create<bool>(this, SetOpen),
        EventCallback.Factory.Create<string>(this, OnSearchChanged),
        EventCallback.Factory.Create(this, OnClear),
        EventCallback.Factory.Create<string>(this, OnCreateItem),
        _wrapperId, _contentId, EffectiveTriggerId, _focusedIndex, focusedItemId, focusedItemValue,
        EventCallback.Factory.Create<int>(this, SetFocusedIndex),
        EventCallback.Factory.Create<string>(this, HandleTypeahead),
        RegisterItem, UnregisterItem, EffectiveInvalid, Required,
        Items, ItemValue, ItemText, ItemGroup, ItemDisabled, ItemDescription, ItemIcon, ItemTemplate, Virtualize, ItemSize)
    {
        Placeholder = Placeholder,
        DescribedBy = FormFieldDescribedBy,
        InsideFormField = InsideFormField,
        ResolveTagLabel = ResolveTagLabel,
    };
}

@* Render the label, control and helper/error as ONE self-contained vertical block so the
   field never splays into a row when dropped in a flex / centered container. Standalone
   form-field structural fix. *@
<div class="flex flex-col items-start">
@if (Label is not null && !InsideFormField)
{
    <label class="block text-sm font-medium mb-1.5">
        @Label
        @if (Required)
        {
            <span class="text-destructive ms-0.5">*</span>
        }
    </label>
}

<CascadingValue Value="context" IsFixed="false">
    <div id="@_wrapperId" class="@WrapperCssClass" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
</CascadingValue>

@if (!InsideFormField)
{
    @if (EffectiveInvalid && !string.IsNullOrEmpty(ErrorText))
    {
        <p class="mt-1 text-xs text-destructive" role="alert" aria-live="polite">@ErrorText</p>
    }
    else if (!string.IsNullOrEmpty(HelperText))
    {
        <p class="mt-1 text-xs text-muted-foreground">@HelperText</p>
    }
}
</div>

@code {
    [CascadingParameter] private FormField.FormFieldContext? FormField { get; set; }

    // Threaded into SelectContext.DescribedBy → SelectTrigger's aria-describedby.
    private string? FormFieldDescribedBy => FormField?.DescribedBy;

    // Inside a FormField, adopt its ControlId as the trigger button's id so the
    // field's <Label For> actually click-focuses the combobox (Base UI Field parity,
    // matching Textarea/DatePicker/TimePicker). Standalone, keep our own generated id.
    // Every internal id use (context, FocusAsync, AutoFocus, popover anchoring) flows
    // through this so the rendered id and the focus/anchor targets stay consistent.
    private string EffectiveTriggerId =>
        !string.IsNullOrEmpty(FormField?.ControlId) ? FormField!.ControlId : _triggerId;

    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Value { get; set; }
    [Parameter] public EventCallback<string?> ValueChanged { get; set; }
    /// <summary>
    /// Popover open state. Bind via <c>@bind-Open</c> when the Select lives inside
    /// a parent that re-renders heavily (e.g. an <c>EditForm</c> with active
    /// validation) — otherwise a parameter cascade can close the popover mid-click.
    /// In the bound (controlled) mode the parent owns state and the popover survives
    /// re-renders. When unbound, the component still functions but is vulnerable to
    /// the cascade-close race; binding is the recommended pattern.
    /// </summary>
    [Parameter] public bool Open { get; set; }
    [Parameter] public EventCallback<bool> OpenChanged { get; set; }

    [Obsolete("Use Open instead. IsOpen will be removed in a future release.")]
    [Parameter] public bool IsOpen { get => Open; set => Open = value; }

    [Obsolete("Use OpenChanged instead. IsOpenChanged will be removed in a future release.")]
    [Parameter] public EventCallback<bool> IsOpenChanged { get => OpenChanged; set => OpenChanged = value; }

    [Parameter] public bool Searchable { get; set; }
    [Parameter] public bool Multiple { get; set; }
    [Parameter] public List<string>? Values { get; set; }
    [Parameter] public EventCallback<List<string>?> ValuesChanged { get; set; }
    [Parameter] public bool Clearable { get; set; }
    [Parameter] public bool Creatable { get; set; }
    [Parameter] public EventCallback<string> OnCreate { get; set; }
    [Parameter] public int MaxDisplayTags { get; set; } = 3;
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public bool IsLoading { get; set; }
    [Parameter] public bool Required { get; set; }
    [Parameter] public bool Invalid { get; set; }
    [Parameter] public string? ErrorText { get; set; }
    [Parameter] public string? HelperText { get; set; }
    [Parameter] public string? Label { get; set; }
    [Parameter] public string? Name { get; set; }
    /// <summary>Custom CSS classes merged onto the Select's wrapper element. Consistent
    /// with every other form component per the library's base API contract.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Convenience placeholder shown by <see cref="SelectTrigger"/> when no value
    /// is selected and the trigger doesn't set its own <c>Placeholder</c>. Lets consumers
    /// write <c>&lt;Select Placeholder="…"&gt;</c> instead of threading it through the trigger
    /// — matching DatePicker / TimePicker / Combobox's top-level placeholder ergonomics.</summary>
    [Parameter] public string? Placeholder { get; set; }
    /// <summary>Focuses the select's trigger button on first render. See
    /// <c>Input.AutoFocus</c> — the HTML autofocus attribute doesn't work in
    /// Blazor WASM, this parameter uses <c>FocusElement</c> after mount.</summary>
    [Parameter] public bool AutoFocus { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    /// <summary>Programmatically focus the trigger button.</summary>
    public ValueTask FocusAsync() => Interop.FocusElement(EffectiveTriggerId);

    private bool _wasOpen;

    // _focusedIndex is a POSITION into NavItems; the rendered highlight and what
    // Enter/Space selects (FocusedItemValue) are read from navItems[_focusedIndex].
    // An external Items/Value data-change while the popover is open (reorder, filter,
    // add/remove, or a same-content refresh that creates a fresh list instance) would
    // leave that index pointing at a DIFFERENT row — silently retargeting the highlight
    // and the Enter/Space selection. Anchor focus by VALUE rather than position so it
    // survives a same-content refresh and follows the item across reorders, mirroring
    // how TrySeedFocusToSelected remaps by value. _focusedValue is the value the index
    // currently points at; null means "no highlight" (_focusedIndex == -1).
    private string? _focusedValue;

    protected override void OnParametersSet()
    {
        // Re-validate the keyboard highlight against the (possibly new) option list.
        // Only meaningful while the popover is open; a closed Select has nothing to
        // re-anchor. We key off _focusedValue (the stable identity) rather than the
        // raw index so the re-anchor still runs after a transient-empty render dropped
        // the index to -1 (the refill restores the highlight onto the same row).
        if (Open && _focusedValue is not null)
        {
            var nav = NavItems;
            // Don't clobber an in-progress highlight on a transient-empty list
            // (e.g. an async Items refresh that flickers empty→refilled): hide the
            // highlight for this render (index out of range) but KEEP _focusedValue
            // so the refill re-anchors onto the same row.
            if (nav.Count == 0)
            {
                _focusedIndex = -1;
            }
            else
            {
                // Follow the previously-focused VALUE to its new position. If it is
                // gone from the refreshed list, drop the highlight (-1) rather than
                // letting the stale index point at an unrelated row.
                var idx = nav.FindIndex(n => n.Value == _focusedValue);
                _focusedIndex = idx;
                if (idx < 0) _focusedValue = null;
            }
        }
        else if (Open && _focusedIndex >= 0)
        {
            // No tracked value (shouldn't normally happen) but a live highlight —
            // clamp the bare index into range so it never points past the list.
            var count = NavItems.Count;
            if (_focusedIndex >= count) _focusedIndex = count - 1;
        }

        // After re-anchoring the existing highlight against the new list, re-run the
        // seed if the SELECTED value changed while the popover stayed open and the
        // highlight is still on the previously-seeded value (battle-wave1 #68).
        ReseedSelectedIfUntouched();
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender && AutoFocus)
        {
            try { await Interop.FocusElement(EffectiveTriggerId); }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
        }

        // Seed keyboard focus to the currently-selected option the first time the
        // listbox opens, so it opens highlighting the current value (Radix / shadcn
        // behaviour) and the first ArrowDown moves from there rather than the top.
        // Runs after render so data-bound NavItems and self-registered SelectItems
        // are present in both modes. Re-armed on close (where SetOpen also resets
        // _focusedIndex), so a fresh open re-seeds.
        // Defer latching until the option list actually exists: a Select opened
        // while its Items are still loading (NavItems empty on the open render)
        // must re-attempt the seed on the later render where options appear,
        // instead of consuming the one-shot early and never highlighting the value.
        if (Open && !_wasOpen && NavItems.Count > 0)
        {
            _wasOpen = true;
            if (TrySeedFocusToSelected())
                StateHasChanged();
        }
        else if (!Open && _wasOpen)
        {
            _wasOpen = false;
        }
    }

    // Sets _focusedIndex to the index of the current value within NavItems, unless
    // the user has already navigated (_focusedIndex >= 0) or there is no match.
    private bool TrySeedFocusToSelected()
    {
        if (_focusedIndex >= 0) return false;
        var nav = NavItems;
        if (nav.Count == 0) return false;
        var selected = Multiple ? Values?.FirstOrDefault() : Value;
        if (string.IsNullOrEmpty(selected)) return false;
        var idx = nav.FindIndex(n => n.Value == selected);
        if (idx < 0) return false;
        _focusedIndex = idx;
        _focusedValue = nav[idx].Value;
        // Remember WHAT we auto-seeded to. If the selected Value later changes while
        // the popover stays open and the highlight is still parked on this seeded
        // value (the user hasn't ArrowDown'd away), OnParametersSet re-seeds to the
        // new value — see ReseedSelectedIfUntouched.
        _seededValue = nav[idx].Value;
        return true;
    }

    // The value the seed-to-selected last auto-highlighted (Radix "open on the
    // current value"). Distinct from _focusedValue, which also tracks user-driven
    // ArrowDown/typeahead moves: _seededValue is ONLY written by the auto-seed, so a
    // mismatch between the two means the user has navigated and we must not re-seed.
    private string? _seededValue;

    // Re-runs the seed-to-selected when the selected Value (single) or first Values
    // entry (multiple) changes WHILE the popover stays open. The one-shot _wasOpen
    // latch makes OnAfterRenderAsync seed only on the first open render; without this,
    // selecting a different value programmatically mid-open (or a parent that swaps
    // Value while the listbox is showing) would leave the highlight stuck on the
    // originally-seeded row. We only move the highlight when it is still parked on the
    // previously-seeded value (untouched), so an explicit user ArrowDown/typeahead —
    // which sets _focusedValue to something other than _seededValue — is never fought.
    private void ReseedSelectedIfUntouched()
    {
        if (!Open) return;
        var selected = Multiple ? Values?.FirstOrDefault() : Value;
        if (string.IsNullOrEmpty(selected)) return;
        // Already highlighting the current selection — nothing to do.
        if (_focusedValue == selected) return;
        // Only re-seed an UNTOUCHED highlight: either nothing is highlighted yet, or
        // the highlight is still the value we previously auto-seeded (user hasn't
        // navigated). A user-driven highlight (_focusedValue != _seededValue) is left
        // alone so we don't yank the keyboard cursor out from under them.
        if (_focusedIndex >= 0 && _focusedValue != _seededValue) return;
        var nav = NavItems;
        var idx = nav.FindIndex(n => n.Value == selected);
        if (idx < 0) return;
        _focusedIndex = idx;
        _focusedValue = nav[idx].Value;
        _seededValue = nav[idx].Value;
    }

    // --- Data-bound mode (non-generic, purely additive) ---
    /// <summary>Optional data source. When set, <see cref="SelectContent"/> renders options from this list instead of ChildContent.</summary>
    [Parameter] public IEnumerable<object>? Items { get; set; }
    /// <summary>Extracts the string value for each item. Defaults to <c>ToString()</c>.</summary>
    [Parameter] public Func<object, string> ItemValue { get; set; } = it => it?.ToString() ?? "";
    /// <summary>Extracts the display label for each item. Defaults to <see cref="ItemValue"/> when null.</summary>
    [Parameter] public Func<object, string>? ItemText { get; set; }
    /// <summary>Optional group key extractor. When set, options are grouped under sticky headers.</summary>
    [Parameter] public Func<object, string?>? ItemGroup { get; set; }
    /// <summary>Optional per-item disabled predicate.</summary>
    [Parameter] public Func<object, bool>? ItemDisabled { get; set; }
    /// <summary>
    /// Optional per-item secondary line (description) extractor. When set and
    /// <see cref="ItemTemplate"/> is null, the default item renderer shows the
    /// description in a smaller, muted line below the label.
    /// </summary>
    [Parameter] public Func<object, string?>? ItemDescription { get; set; }
    /// <summary>
    /// Optional per-item leading icon. Receives the raw item object and returns a
    /// RenderFragment (typically a single <c>&lt;Blazicon&gt;</c>). Rendered before
    /// the label when <see cref="ItemTemplate"/> is null. Return <c>null</c> per item
    /// to mix iconed and non-iconed rows.
    /// </summary>
    [Parameter] public Func<object, RenderFragment?>? ItemIcon { get; set; }
    /// <summary>Optional custom render fragment for an item's content. Receives the raw item object.</summary>
    [Parameter] public RenderFragment<object>? ItemTemplate { get; set; }
    /// <summary>When <c>true</c> and <see cref="Items"/> is set, uses Blazor's Virtualize component for the option list.</summary>
    [Parameter] public bool Virtualize { get; set; }
    /// <summary>Estimated pixel height of each option row used by the Virtualize component. Default 36.</summary>
    [Parameter] public float ItemSize { get; set; } = 36f;

    private bool EffectiveInvalid => Invalid || FormField?.HasError == true;
    private bool InsideFormField => FormField is not null;

    // "relative" anchors the absolutely-positioned dropdown; "w-full" makes the Select a
    // block-level form control that fills its container by default (like Input) — without it
    // the wrapper shrink-wraps under the root's `items-start`, so SelectTrigger's own w-full
    // resolves against a collapsed box and the control never fills. Class is merged LAST so a
    // consumer can still pin a fixed/constrained width (tailwind-merge: last width wins).
    private string WrapperCssClass => Cx.Merge("relative w-full", Class);

    private readonly string _wrapperId = LumeoIds.New("select");
    private readonly string _contentId = LumeoIds.New("select-content");
    private readonly string _triggerId = LumeoIds.New("select-trigger");
    private string SearchText { get; set; } = "";
    private int _focusedIndex = -1;
    private readonly List<(string Id, string Value, string Text, bool Disabled, RenderFragment? Label)> _items = new();
    // Composition-mode SelectItem instances only EXIST in the render tree while
    // Context.IsOpen (SelectContent gates its whole subtree on it), so they unregister
    // themselves (Dispose -> UnregisterItem) the instant the popover closes — _items is
    // empty exactly when the CLOSED trigger needs a label for its Multiple-mode tags.
    // This cache is fed by every RegisterItem call but, unlike _items, is never cleared
    // by UnregisterItem/close: once a value's label has been seen at least once (the
    // popover was opened while that SelectItem was visible), it is remembered for the
    // life of the component, so a closed-trigger tag rendered after that still resolves
    // correctly. Does NOT cover a value pre-selected before the popover was EVER opened
    // in this session — there is no label to remember yet; ChildContent/TagLabel are the
    // reliable fallback for that case.
    private readonly Dictionary<string, RenderFragment> _labelCache = new();
    // Type-to-jump buffer (non-searchable listbox). Same idle-reset semantics the
    // menu family uses; here it drives _focusedIndex instead of DOM focus.
    private readonly Lumeo.Services.MenuTypeahead _typeahead = new();

    private void RegisterItem(string id, string value, string text, bool disabled, RenderFragment? label)
    {
        // Upsert: a re-registration with the same id (e.g. an item's Disabled or
        // search text changed while the menu is open) must UPDATE the cached entry,
        // not be ignored — otherwise NavItems keeps the stale state and keyboard
        // nav / Enter could land on an item that is now disabled.
        var idx = _items.FindIndex(i => i.Id == id);
        if (idx < 0)
            _items.Add((id, value, text, disabled, label));
        else
            _items[idx] = (id, value, text, disabled, label);

        if (label is not null) _labelCache[value] = label;
    }

    // Resolves the display label for a SELECTED value shown as a Multiple-mode trigger
    // tag. Composition mode: find the SelectItem that registered this value and re-render
    // ITS ChildContent (the same RenderFragment, rendered a second time in the trigger —
    // a RenderFragment is just a delegate, so invoking it in two places is the normal,
    // idiomatic way to reuse a child's content elsewhere) — checked via the persistent
    // _labelCache so a value seen at least once while the popover was open still resolves
    // after it closes. Data-bound mode: resolve via ItemText/ItemValue, the same functions
    // SelectContent already uses for the option list. Falls back to the raw value when
    // nothing matches (e.g. a value pre-selected before the popover was ever opened, or a
    // stale selected value whose item was removed) — previously the trigger ALWAYS showed
    // this raw value, never a resolved label (Codex P2).
    private RenderFragment ResolveTagLabel(string value)
    {
        if (_labelCache.TryGetValue(value, out var cached)) return cached;

        if (Items is not null)
        {
            var match = Items.FirstOrDefault(it => ItemValue(it) == value);
            if (match is not null)
            {
                var text = ItemText?.Invoke(match) ?? ItemValue(match);
                return b => b.AddContent(0, text);
            }
        }

        return b => b.AddContent(0, value);
    }

    private void UnregisterItem(string id)
    {
        _items.RemoveAll(i => i.Id == id);
    }

    // Keyboard-nav source of truth. Composition mode: SelectItem instances self-register
    // into _items. Data-bound mode: bound rows are rendered inline by SelectContent (no
    // component instance to register), so derive the list from the same filtered + grouped
    // sequence the content renders, skipping disabled items so ArrowDown/Up, Home/End and
    // Enter can never land on them. Ids must mirror SelectContent.RenderBoundItem.
    // Composition mode excludes disabled items from the nav set (parity with bound
    // mode + Radix): they still render, but ArrowDown/Up/Home/End, type-to-jump and
    // Enter-select skip them. Without this, keyboard nav could land on — and Enter
    // could select — a disabled option (the click path already guards, the keyboard
    // path did not).
    private List<(string Id, string Value, string Text)> NavItems => Items is null
        ? _items.Where(i => !i.Disabled).Select(i => (i.Id, i.Value, i.Text)).ToList()
        : BuildBoundNavItems();

    private List<(string Id, string Value, string Text)> BuildBoundNavItems()
    {
        var result = new List<(string Id, string Value, string Text)>();
        if (Items is null) return result;

        IEnumerable<object> source = Items;
        if (Searchable && !string.IsNullOrEmpty(SearchText))
        {
            source = source.Where(item =>
            {
                var text = ItemText?.Invoke(item) ?? ItemValue(item);
                return text.Contains(SearchText, StringComparison.OrdinalIgnoreCase);
            });
        }
        // Grouped rendering flattens GroupBy order (groups appear at their first occurrence),
        // so mirror it — otherwise the focused index walks the source order while the eye
        // follows the grouped order. The Virtualize branch renders ungrouped.
        if (ItemGroup is not null && !Virtualize)
            source = source.GroupBy(i => ItemGroup(i) ?? "").SelectMany(g => g);

        // Index increments for EVERY item (disabled included) so it stays the item's position
        // in the rendered sequence — SelectContent.RenderBoundItem assigns the same per-position
        // id. Disabled items are skipped from the nav list but still consume an index slot so
        // the enabled rows keep the id their rendered counterpart computed. Using the position
        // (not value.GetHashCode()) makes the ids collision-proof.
        var index = 0;
        foreach (var item in source)
        {
            var i = index++;
            if (ItemDisabled?.Invoke(item) == true) continue;
            var value = ItemValue(item);
            // Typeahead/search match against the display text (same source the search
            // filter uses), falling back to the value when no ItemText is supplied.
            var text = ItemText?.Invoke(item) ?? value;
            result.Add(($"{_contentId}-bound-{i}", value, text));
        }
        return result;
    }

    private async Task SetFocusedIndex(int index)
    {
        var nav = NavItems;
        var count = nav.Count;
        if (count == 0) return;
        if (index < 0) index = 0;
        if (index >= count) index = count - 1;
        _focusedIndex = index;
        _focusedValue = nav[index].Value;
        StateHasChanged();
        await Task.CompletedTask;
    }

    // Type-to-jump: accumulate printable keystrokes and move _focusedIndex to the
    // first option whose display text starts with the query (Radix's getNextMatch).
    // Only wired for the non-searchable listbox — when Searchable, printable keys
    // belong to the search input. Matches against NavItems' Text so it respects each
    // mode's nav set (bound mode already excludes disabled rows).
    private void HandleTypeahead(string key)
    {
        var nav = NavItems;
        if (nav.Count == 0) return;
        var query = _typeahead.Push(key);

        // A repeated single char ("aaa") cycles through items starting with that
        // char rather than searching for the literal repeat.
        var isRepeated = query.Length > 1 && query.All(c => c == query[0]);
        var search = isRepeated ? query[0].ToString() : query;

        // Single-char query starts the scan just past the current item (so the same
        // key cycles); a multi-char refinement starts at the current item (so a
        // continued query keeps the current match when it still fits).
        var current = _focusedIndex < 0 ? -1 : _focusedIndex;
        var start = search.Length == 1 ? current + 1 : current;
        if (start < 0) start = 0;

        for (var n = 0; n < nav.Count; n++)
        {
            var idx = (start + n) % nav.Count;
            if (nav[idx].Text.StartsWith(search, StringComparison.OrdinalIgnoreCase))
            {
                _focusedIndex = idx;
                _focusedValue = nav[idx].Value;
                StateHasChanged();
                return;
            }
        }
    }

    private async Task OnValueSelected(string value)
    {
        if (Multiple)
        {
            var current = Values ?? new List<string>();
            if (current.Contains(value))
            {
                current = current.Where(v => v != value).ToList();
            }
            else
            {
                current = new List<string>(current) { value };
            }
            Values = current.Count > 0 ? current : null;
            await ValuesChanged.InvokeAsync(Values);
        }
        else
        {
            Value = value;
            await ValueChanged.InvokeAsync(value);
            await SetOpen(false);
        }
    }

    private async Task SetOpen(bool value)
    {
        Open = value;
        if (!value)
        {
            SearchText = "";
            _focusedIndex = -1;
            _focusedValue = null;
            _seededValue = null;
            _items.Clear();
            _typeahead.Reset();
        }
        await OpenChanged.InvokeAsync(value);
    }

    private Task OnSearchChanged(string text)
    {
        SearchText = text;
        _focusedIndex = -1;
        _focusedValue = null;
        // Do NOT clear _items here: still-visible SelectItems keep their _registered flag
        // and would never re-register, leaving keyboard nav dead after the first keystroke.
        // Items hidden by the new filter unregister themselves (OnParametersSet/Dispose),
        // so the registry stays in sync on its own.
        return Task.CompletedTask;
    }

    private async Task OnClear()
    {
        if (Multiple)
        {
            Values = null;
            await ValuesChanged.InvokeAsync(null);
        }
        else
        {
            Value = null;
            await ValueChanged.InvokeAsync(null);
        }
    }

    private async Task OnCreateItem(string value)
    {
        await OnCreate.InvokeAsync(value);
        if (Multiple)
        {
            var current = Values ?? new List<string>();
            current = new List<string>(current) { value };
            Values = current;
            await ValuesChanged.InvokeAsync(Values);
        }
        else
        {
            Value = value;
            await ValueChanged.InvokeAsync(value);
            await SetOpen(false);
        }
        SearchText = "";
    }

    public record SelectContext(
        string? Value, bool IsOpen, bool Searchable, string SearchText,
        bool Multiple, List<string>? Values, bool IsLoading, bool Disabled, bool Clearable, bool Creatable, int MaxDisplayTags,
        EventCallback<string> OnSelect, EventCallback<bool> SetOpen, EventCallback<string> OnSearch,
        EventCallback OnClear, EventCallback<string> OnCreateItem,
        string WrapperId, string ContentId, string TriggerId, int FocusedIndex, string? FocusedItemId, string? FocusedItemValue,
        EventCallback<int> SetFocusedIndex,
        EventCallback<string> OnTypeahead,
        Action<string, string, string, bool, RenderFragment?> RegisterItem, Action<string> UnregisterItem,
        bool Invalid, bool Required,
        // Data-bound mode params (null when composition mode)
        IEnumerable<object>? Items,
        Func<object, string> ItemValue,
        Func<object, string>? ItemText,
        Func<object, string?>? ItemGroup,
        Func<object, bool>? ItemDisabled,
        Func<object, string?>? ItemDescription,
        Func<object, RenderFragment?>? ItemIcon,
        RenderFragment<object>? ItemTemplate,
        bool Virtualize,
        float ItemSize)
    {
        /// <summary>Top-level placeholder set on <c>&lt;Select&gt;</c>; SelectTrigger uses it
        /// as a fallback when its own Placeholder is unset. Init-only so the positional
        /// constructor above stays source-compatible.</summary>
        public string? Placeholder { get; init; }

        /// <summary>Id of the parent FormField's rendered help/error text, applied as
        /// <c>aria-describedby</c> on the trigger so a screen reader announces it on focus.
        /// Null outside a FormField. Init-only to keep the positional ctor source-compatible.</summary>
        public string? DescribedBy { get; init; }

        /// <summary>True when the parent <c>&lt;Select&gt;</c> is inside a FormField, so
        /// <see cref="TriggerId"/> is the FormField's ControlId (the field <c>&lt;Label For&gt;</c> targets it).
        /// SelectTrigger uses this to strip a consumer-splatted <c>id</c> from its attribute bag so it cannot
        /// override the FormField-owned trigger id. Init-only to keep the positional ctor source-compatible.</summary>
        public bool InsideFormField { get; init; }

