        /// and finally to the raw value itself when nothing matches. Init-only to keep the positional
        /// constructor source-compatible.</summary>
        public Func<string, RenderFragment>? ResolveTagLabel { get; init; }
    }
}

@namespace Lumeo
@implements IAsyncDisposable
@using Microsoft.AspNetCore.Components.Web.Virtualization

@if (Context.IsOpen)
{
    <div id="@Context.ContentId" role="listbox" aria-multiselectable="@(Context.Multiple ? "true" : null)" class="@CssClass"
         @onkeydown="HandleKeyDown" tabindex="-1" @attributes="AdditionalAttributes">
        @if (Context.Searchable)
        {
            <div class="px-1 pb-1">
                @* @onkeydown:stopPropagation is required — the input focuses INTO the listbox
                   (see OnAfterRenderAsync), so without it every keydown bubbles to the outer
                   div's own @onkeydown="HandleKeyDown" and fires HandleKeyDown TWICE for the
                   same keystroke: Enter invoked Context.OnSelect twice for the same
                   FocusedItemValue, which in Multiple mode added the value then immediately
                   removed it again (keyboard selection appeared to do nothing), and in Single
                   mode double-fired ValueChanged (Codex P2). Mirrors Cascader/TreeSelect's
                   search input, which already stops propagation for this exact reason. *@
                <input type="text" id="@($"{Context.ContentId}-search")" class="w-full rounded-sm border border-border/40 bg-background px-2 py-1 text-sm outline-none focus:ring-1 focus:ring-ring placeholder:text-muted-foreground"
                    placeholder="@L["Combobox.SearchPlaceholder"]"
                    value="@Context.SearchText"
                    @oninput="OnInput"
                    @onkeydown="HandleKeyDown"
                    @onkeydown:stopPropagation="true"
                    @onclick:stopPropagation="true" />
            </div>
        }

        <div class="overflow-y-auto min-h-0 flex-1">
        @if (Context.IsLoading)
        {
            <div class="flex items-center justify-center py-4">
                <Spinner Size="Lumeo.Size.Sm" class="text-muted-foreground" />
            </div>
        }
        else if (Context.Items is not null)
        {
            @* Data-bound mode: render items from the Items collection *@
            var filteredItems = FilteredItems;
            @if (Context.Virtualize)
            {
                @* Pair each item with its positional index up-front. IndexOf would return
                   the FIRST equal item, so duplicate values collapsed to one id and desynced
                   from Select.BuildBoundNavItems' positional indexing. *@
                var indexedItems = filteredItems.Select((it, idx) => (Item: it, Index: idx)).ToList();
                <Virtualize Items="@indexedItems" Context="entry" ItemSize="@Context.ItemSize">
                    @RenderBoundItem(entry.Item, entry.Index)
                </Virtualize>
            }
            else if (Context.ItemGroup is not null)
            {
                @* Grouped rendering. Walk groups in order with a running index so each row's id
                   matches the flattened (GroupBy→SelectMany) order the parent uses for nav. *@
                var boundIndex = 0;
                @foreach (var group in filteredItems.GroupBy(i => Context.ItemGroup(i) ?? ""))
                {
                    <div role="group">
                        @if (!string.IsNullOrEmpty(group.Key))
                        {
                            <div class="px-2 py-1.5 text-sm font-semibold">@group.Key</div>
                        }
                        @foreach (var item in group)
                        {
                            @RenderBoundItem(item, boundIndex++)
                        }
                    </div>
                }
            }
            else
            {
                @for (var i = 0; i < filteredItems.Count; i++)
                {
                    @RenderBoundItem(filteredItems[i], i)
                }
            }

            @if (Context.Creatable && !string.IsNullOrWhiteSpace(Context.SearchText))
            {
                <button type="button" class="relative flex w-full cursor-default select-none items-center gap-2 rounded-sm py-1.5 ps-2 pe-8 text-sm outline-none hover:bg-accent hover:text-accent-foreground"
                        @onclick="HandleCreate">
                    <SvgGlyph Svg="@(LumeoIcons.Plus)" class="h-3.5 w-3.5" />
                    <span>@string.Format(L["Combobox.Create"], Context.SearchText)</span>
                </button>
            }
        }
        else
        {
            @ChildContent

            @if (Context.Creatable && !string.IsNullOrWhiteSpace(Context.SearchText))
            {
                <button type="button" class="relative flex w-full cursor-default select-none items-center gap-2 rounded-sm py-1.5 ps-2 pe-8 text-sm outline-none hover:bg-accent hover:text-accent-foreground"
                        @onclick="HandleCreate">
                    <SvgGlyph Svg="@(LumeoIcons.Plus)" class="h-3.5 w-3.5" />
                    <span>@string.Format(L["Combobox.Create"], Context.SearchText)</span>
                </button>
            }
        }
        </div>
    </div>
}

@inject IComponentInteropService Interop
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@code {
    [CascadingParameter] public Select.SelectContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _registered;

    /// <summary>Items filtered by the current search text (data-bound mode only).</summary>
    private List<object> FilteredItems
    {
        get
        {
            if (Context.Items is null) return [];
            if (!Context.Searchable || string.IsNullOrEmpty(Context.SearchText))
                return Context.Items.ToList();

            return Context.Items.Where(item =>
            {
                var text = Context.ItemText?.Invoke(item) ?? Context.ItemValue(item);
                return text.Contains(Context.SearchText, StringComparison.OrdinalIgnoreCase);
            }).ToList();
        }
    }

    private RenderFragment RenderBoundItem(object item, int index) => builder =>
    {
        var value = Context.ItemValue(item);
        var isSelected = Context.Multiple
            ? Context.Values != null && Context.Values.Contains(value)
            : Context.Value == value;
        var isDisabled = Context.ItemDisabled?.Invoke(item) ?? false;
        // Index-based, not value.GetHashCode(): two values whose hashes collide would
        // otherwise share a DOM id, so aria-activedescendant / Enter would land on the
        // wrong row. The index is the item's position in the filtered (+ grouped) sequence
        // — the same basis Select.BuildBoundNavItems uses, keeping the two in sync.
        var itemId = $"{Context.ContentId}-bound-{index}";

        // Bound items are rendered inline (no component instance), so they cannot self-register
        // the way SelectItem does. Keyboard nav instead derives its list on the parent Select
        // (NavItems) from the same filtered/grouped sequence rendered here — the deterministic
        // itemId above is the contract between the two. We render a plain button that matches
        // SelectItem's markup so styling stays consistent.

        var isFocused = Context.FocusedItemId == itemId;

        builder.OpenElement(0, "button");
        builder.AddAttribute(1, "type", "button");
        builder.AddAttribute(2, "id", itemId);
        builder.AddAttribute(3, "role", "option");
        builder.AddAttribute(4, "aria-selected", isSelected.ToString().ToLower());
        builder.AddAttribute(5, "aria-disabled", isDisabled.ToString().ToLower());
        var cssClass = Cx.Join(
            "relative flex w-full select-none items-center gap-2 rounded-sm py-1.5 ps-2 pe-8 text-sm outline-none",
            isDisabled ? "opacity-50 cursor-not-allowed pointer-events-none" : "cursor-pointer hover:bg-accent hover:text-accent-foreground",
            Cx.When(isFocused && !isDisabled, "bg-accent text-accent-foreground"));
        builder.AddAttribute(6, "class", cssClass);
        if (!isDisabled)
        {
            builder.AddAttribute(7, "onclick", EventCallback.Factory.Create(this, () => Context.OnSelect.InvokeAsync(value)));
        }
        builder.OpenElement(8, "span");
        builder.AddAttribute(9, "class", "flex h-3.5 w-3.5 shrink-0 items-center justify-center");
        if (isSelected)
        {
            builder.OpenComponent<SvgGlyph>(10);
            builder.AddAttribute(11, "Svg", LumeoIcons.Check);
            builder.AddAttribute(12, "class", "h-3.5 w-3.5");
            builder.CloseComponent();
        }
        builder.CloseElement(); // span

        if (Context.ItemTemplate is not null)
        {
            builder.AddContent(13, Context.ItemTemplate(item));
        }
        else
        {
            // Default renderer: optional leading icon, label, optional sub-line description.
            // ItemIcon and ItemDescription can return null per item so iconed and un-iconed
            // rows can mix in the same list without forcing every row to reserve the column.
            var icon = Context.ItemIcon?.Invoke(item);
            if (icon is not null)
            {
                builder.OpenElement(13, "span");
                builder.AddAttribute(14, "class", "flex h-4 w-4 shrink-0 items-center justify-center text-muted-foreground");
                builder.AddContent(15, icon);
                builder.CloseElement();
            }

            var label = Context.ItemText?.Invoke(item) ?? value;
            var description = Context.ItemDescription?.Invoke(item);
            if (!string.IsNullOrEmpty(description))
            {
                builder.OpenElement(16, "span");
                builder.AddAttribute(17, "class", "flex min-w-0 flex-col");
                builder.OpenElement(18, "span");
                builder.AddAttribute(19, "class", "truncate");
                builder.AddContent(20, label);
                builder.CloseElement();
                builder.OpenElement(21, "span");
                builder.AddAttribute(22, "class", "truncate text-xs text-muted-foreground");
                builder.AddContent(23, description);
                builder.CloseElement();
                builder.CloseElement();
            }
            else
            {
                builder.AddContent(24, label);
            }
        }
        builder.CloseElement(); // button
    };

    private string CssClass => Cx.Merge("fixed z-50 min-w-[8rem] max-h-96 flex flex-col overflow-hidden rounded-md border border-border/40 bg-popover p-1 text-popover-foreground shadow-lg animate-fade-in", Class);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (Context.IsOpen && !_registered)
        {
            await Interop.PositionFixed(Context.ContentId, Context.WrapperId, "start", true);
            // Exclude the trigger from outside-close (same as Cascader): without it, mousedown
            // on the open trigger fires the outside handler AND the trigger's own click toggle,
            // racing close-then-reopen instead of reliably closing.
            await Interop.RegisterClickOutside(Context.ContentId, Context.TriggerId, async () =>
            {
                await Context.SetOpen.InvokeAsync(false);
                await InvokeAsync(StateHasChanged);
            });
            // Suppress the browser default for the listbox navigation keys so they
            // move the focused option instead of scrolling the page (the keys are
            // handled in HandleKeyDown). SkipEditable keeps the search input's own
            // caret keys (Home/End) and typing alive when the Select is Searchable.
            await Interop.RegisterPreventDefaultKeys(Context.ContentId, new[]
            {
                new PreventDefaultKeyRule("ArrowDown", SkipEditable: true),
                new PreventDefaultKeyRule("ArrowUp", SkipEditable: true),
                new PreventDefaultKeyRule("Home", SkipEditable: true),
                new PreventDefaultKeyRule("End", SkipEditable: true),
                // Space selects the focused option (APG listbox); suppress its
                // page-scroll default. SkipEditable keeps Space typing a literal
                // space in the search input when the Select is Searchable.
                new PreventDefaultKeyRule(" ", SkipEditable: true),
            });
            // Move focus INTO the popover so HandleKeyDown + the preventDefault above
            // actually receive keys — focus otherwise stays on the trigger button (a
            // DOM sibling), so arrows scrolled the page and listbox nav silently broke
            // in a real browser. Searchable -> the search input (so the user can type);
            // otherwise the listbox container. saveFocus first so close returns focus to
            // the trigger (WCAG 2.4.3); no Tab trap, so Tab still leaves the open Select.
            try { await Interop.SaveFocus(Context.ContentId); } catch (JSDisconnectedException) { }
            var focusId = Context.Searchable ? $"{Context.ContentId}-search" : Context.ContentId;
            try { await Interop.FocusElement(focusId); } catch (JSDisconnectedException) { }
            _registered = true;
        }
        else if (!Context.IsOpen && _registered)
        {
            await Cleanup();
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "Escape":
                await Context.SetOpen.InvokeAsync(false);
                break;
            case "ArrowDown":
                await Context.SetFocusedIndex.InvokeAsync(Context.FocusedIndex + 1);
                break;
            case "ArrowUp":
                await Context.SetFocusedIndex.InvokeAsync(Context.FocusedIndex > 0 ? Context.FocusedIndex - 1 : 0);
                break;
            case "Home":
                // Jump to the first option (APG listbox) — but only for the
                // non-searchable listbox; when Searchable, Home moves the caret
                // to the start of the search input text instead.
                if (!Context.Searchable)
                    await Context.SetFocusedIndex.InvokeAsync(0);
                break;
            case "End":
                // Jump to the last option (APG listbox) — but only for the
                // non-searchable listbox; when Searchable, End moves the caret
                // to the end of the search input text instead.
                if (!Context.Searchable)
                    await Context.SetFocusedIndex.InvokeAsync(int.MaxValue);
                break;
            case "Enter":
                if (Context.FocusedItemValue is not null)
                    await Context.OnSelect.InvokeAsync(Context.FocusedItemValue);
                break;
            case " ":
                // Space selects the focused option (APG listbox) — but only for the
                // non-searchable listbox; when Searchable, Space types into the filter.
                if (!Context.Searchable && Context.FocusedItemValue is not null)
                    await Context.OnSelect.InvokeAsync(Context.FocusedItemValue);
                break;
            default:
                // Type-to-jump on a printable key. Non-searchable listbox only — when
                // Searchable the keystroke belongs to the search input. Modifier combos
                // (Ctrl/Alt/Meta shortcuts) are never typeahead.
                if (!Context.Searchable
                    && !e.CtrlKey && !e.AltKey && !e.MetaKey
                    && Lumeo.Services.MenuTypeahead.IsTypeaheadKey(e.Key))
                {
                    await Context.OnTypeahead.InvokeAsync(e.Key);
                }
                break;
        }
    }

    private async Task OnInput(ChangeEventArgs e)
    {
        await Context.OnSearch.InvokeAsync(e.Value?.ToString() ?? "");
    }

    private async Task HandleCreate()
    {
        await Context.OnCreateItem.InvokeAsync(Context.SearchText);
    }

    private async Task Cleanup()
    {
        try { await Interop.UnpositionFixed(Context.ContentId); } catch (JSDisconnectedException) { }
        try { await Interop.UnregisterClickOutside(Context.ContentId); } catch (JSDisconnectedException) { }
        try { await Interop.UnregisterPreventDefaultKeys(Context.ContentId); } catch (JSDisconnectedException) { }
        // Return focus to the trigger that opened the Select (WCAG 2.4.3) — e.g. after
        // Escape in Searchable mode focus was in the search input, which is now gone.
        try { await Interop.RestoreFocus(Context.ContentId); } catch (JSDisconnectedException) { }
        _registered = false;
    }

    public async ValueTask DisposeAsync()
    {
        if (_registered) await Cleanup();
    }
}

@namespace Lumeo
@implements IDisposable

@* Composition-mode grouping for Select. Wrap SelectItems (or nested SelectGroups
   for multi-level grouping) under a labelled, optionally collapsible header.
   The group hides itself when an active search filters out all of its descendants,
   and — in Multiple mode — can offer a group-level select-all checkbox. Mirrors
   the ComboboxGroup machinery so both pickers behave the same. *@

@* IsFixed=false: SelectGroupContext is mutable (SetExpanded, RegisterItem). Fixed
   cascades skip re-binding when the cascaded value changes — even though the instance
   reference stays the same, descendants like SelectItem must re-evaluate cascaded reads
   on mutation, so we drop the fixed optimization to keep the contract honest. *@
<CascadingValue Value="_groupContext" IsFixed="false">
    <div role="group" aria-labelledby="@_groupContext.LabelId"
         class="@Cx.Join(Cx.When(_isHidden, "hidden"), CssClass)" @attributes="AdditionalAttributes">

        @if (!string.IsNullOrEmpty(Label))
        {
            <div id="@_groupContext.LabelId"
                 class="@HeaderCss"
                 style="@IndentStyle"
                 role="@(Collapsible ? "button" : null)"
                 tabindex="@(Collapsible ? "0" : null)"
                 aria-expanded="@(Collapsible ? _expanded.ToString().ToLowerInvariant() : null)"
                 @onclick="OnHeaderClick"
                 @onkeydown="OnHeaderKeyDown">

                @if (Collapsible)
                {
                    <SvgGlyph Svg="@(LumeoIcons.ChevronRight)"
                              class="@Cx.Join("h-3.5 w-3.5 shrink-0 transition-transform", Cx.When(_expanded, "rotate-90"))" />
                }

                @if (Context.Multiple && GroupSelect)
                {
                    @* stopPropagation on keydown prevents Space/Enter on the focused
                       checkbox from also firing the header's OnHeaderKeyDown (which would
                       toggle collapse on every selection). *@
                    <span class="flex h-3.5 w-3.5 items-center justify-center shrink-0 rounded-sm border border-input focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-1"
                          role="checkbox" aria-checked="@GroupCheckedState"
                          tabindex="0"
                          @onclick="ToggleGroupSelection" @onclick:stopPropagation="true"
                          @onkeydown="OnCheckboxKeyDown" @onkeydown:stopPropagation="true">
                        @if (_allSelected)
                        {
                            <SvgGlyph Svg="@(LumeoIcons.Check)" class="h-3.5 w-3.5" />
                        }
                        else if (_anySelected)
                        {
                            <SvgGlyph Svg="@(LumeoIcons.Minus)" class="h-3.5 w-3.5" />
                        }
                    </span>
                }

                <span class="@Cx.Merge("truncate", LabelClass)">@Label</span>
            </div>
        }

        @* Always render ChildContent so descendant items register with the group even when
           collapsed — required for GroupSelect's tri-state + select-all semantics to keep
           working on a collapsed group. Visual hiding is done via CSS so the items stay
           mounted; SelectItem itself drops out of keyboard navigation when its group is
           collapsed (it sets Visible=false and unregisters from Select's _items list). *@
        <div class="@Cx.When(!_expanded, "hidden")">
            @ChildContent
        </div>
    </div>
</CascadingValue>

@code {
    [CascadingParameter] public Select.SelectContext Context { get; set; } = default!;
    // A parent group, present only for nested (multi-level) grouping.
    [CascadingParameter] public SelectGroupContext? ParentGroup { get; set; }

    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Group header text. When null/empty no header renders (still nests its items).</summary>
    [Parameter] public string? Label { get; set; }

    /// <summary>Extra classes for the group label — theming hook for the header.</summary>
    [Parameter] public string? LabelClass { get; set; }

    /// <summary>When true the header toggles the group open/closed. Collapsed groups hide their items.</summary>
    [Parameter] public bool Collapsible { get; set; }

    /// <summary>Initial expanded state for a <see cref="Collapsible"/> group. Default expanded.</summary>
    [Parameter] public bool DefaultExpanded { get; set; } = true;

    /// <summary>
    /// In <c>Multiple</c> mode, render a tri-state checkbox on the header that selects /
    /// deselects every descendant item in one click. Disabled descendants are skipped.
    /// </summary>
    [Parameter] public bool GroupSelect { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private SelectGroupContext _groupContext = default!;
    // User's explicit expand state (header toggle). Effective expansion also force-opens
    // while a search is active so matches inside a collapsed group stay reachable.
    private bool _userExpanded = true;
    private bool _expanded => !Collapsible || HasActiveSearch || _userExpanded;

    // Depth drives the left-indent for multi-level grouping (Category -> Subcategory).
    private int Depth => (ParentGroup?.Depth ?? -1) + 1;
    private bool _isHidden;

    private string IndentStyle => Depth > 0 ? $"padding-left:{0.5 + Depth * 0.75:0.###}rem" : "";

    private string CssClass => Cx.Merge("p-1", Class);

    private string HeaderCss => Cx.Join(
        "flex items-center gap-1.5 px-2 py-1.5 text-xs font-semibold text-muted-foreground",
        Cx.When(Collapsible, "cursor-pointer select-none hover:text-foreground focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-1 rounded-sm"));

    protected override void OnInitialized()
    {
        _userExpanded = DefaultExpanded;
        _groupContext = new SelectGroupContext(LumeoIds.New("select-label"), Depth, OnChildrenChanged, _expanded, ParentGroup);
        ParentGroup?.RegisterChild(_groupContext);
    }

    protected override void OnParametersSet()
    {
        // Keep the cascaded context's IsExpanded in sync so descendant SelectItems see
        // collapse/expand transitions and re-evaluate their Visible state for kbd nav.
        _groupContext.SetExpanded(_expanded);
        RecomputeVisibility();
    }

    // Only matters when the Select is Searchable AND has search text — otherwise items
    // never disappear and the group is always visible.
    private bool HasActiveSearch => Context.Searchable && !string.IsNullOrEmpty(Context.SearchText);

    private void OnChildrenChanged()
    {
        RecomputeVisibility();
        InvokeAsync(StateHasChanged);
        // Bubble up: a nested visibility change must let the parent group re-evaluate its
        // own _isHidden too, otherwise an outer group can stay hidden after the inner one's
        // descendants come back into view.
        ParentGroup?.NotifyChildrenChanged();
    }

    private void RecomputeVisibility()
        => _isHidden = HasActiveSearch && _groupContext.VisibleDescendantCount == 0;

    private void OnHeaderClick()
    {
        if (!Collapsible || HasActiveSearch) return;
        _userExpanded = !_userExpanded;
        _groupContext.SetExpanded(_expanded);
    }

    private void OnHeaderKeyDown(KeyboardEventArgs e)
    {
        if (!Collapsible) return;
        if (e.Key == "Enter" || e.Key == " " || e.Key == "Spacebar")
        {
            OnHeaderClick();
        }
    }

    // async Task (not void) so ToggleGroupSelection's exceptions propagate and Blazor
    // re-renders on completion the same way the @onclick path does.
    private async Task OnCheckboxKeyDown(KeyboardEventArgs e)
    {
        if (e.Key != "Enter" && e.Key != " " && e.Key != "Spacebar") return;
        await ToggleGroupSelection();
    }

    // --- Group-level selection (Multiple mode) ---

    private bool _allSelected;
    private bool _anySelected;

    private string GroupCheckedState => _allSelected ? "true" : _anySelected ? "mixed" : "false";

    private async Task ToggleGroupSelection()
    {
        // Skip disabled descendants so a group-toggle never selects a value the item itself
        // prevents selecting. When a search is active, scope the toggle to the visible
        // matches only — "select all" should mean "select what the user can see right now".
        var values = (HasActiveSearch
            ? _groupContext.VisibleSelectableDescendantValues
            : _groupContext.SelectableDescendantValues).ToList();
        if (values.Count == 0) return;
        var selectAll = !_allSelected;
        foreach (var v in values)
        {
            var isSelected = Context.Values?.Contains(v) == true;
            if (selectAll != isSelected)
                await Context.OnSelect.InvokeAsync(v);
        }
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (!Context.Multiple || !GroupSelect) return;
        // Aggregation also ignores disabled descendants — they aren't selectable so they
        // shouldn't count towards "all" being checked. Mirror ToggleGroupSelection's
        // search-scope so the tri-state reflects "all visible matches" while filtering.
        var values = (HasActiveSearch
            ? _groupContext.VisibleSelectableDescendantValues
            : _groupContext.SelectableDescendantValues).ToList();
        var all = values.Count > 0 && values.All(v => Context.Values?.Contains(v) == true);
        var any = values.Any(v => Context.Values?.Contains(v) == true);
        if (all != _allSelected || any != _anySelected)
        {
            _allSelected = all;
            _anySelected = any;
            InvokeAsync(StateHasChanged);
        }
    }

    public void Dispose() => ParentGroup?.UnregisterChild(_groupContext);

    /// <summary>
    /// Cascaded to a group's descendants. SelectItems report their value + current
    /// search-visibility + disabled state here; nested groups register themselves so
    /// empty-hiding and group selection aggregate across multiple levels. Exposes
    /// <see cref="LabelId"/> for <c>SelectLabel</c> and <see cref="IsExpanded"/> for
    /// descendants that need to react to collapse (SelectItem uses it to drop out of
    /// keyboard navigation when its group is collapsed).
    /// </summary>
    public sealed class SelectGroupContext
    {
        private readonly Action _onChanged;
        private readonly Dictionary<string, (string Value, bool Visible, bool Disabled)> _items = new();
        private readonly List<SelectGroupContext> _childGroups = new();
        private readonly SelectGroupContext? _parent;

        public SelectGroupContext(string labelId, int depth, Action onChanged, bool isExpanded, SelectGroupContext? parent)
        {
            LabelId = labelId;
            Depth = depth;
            IsExpanded = isExpanded;
            _parent = parent;
            _onChanged = onChanged;
        }

        /// <summary>Stable id used by <c>SelectLabel</c> for <c>aria-labelledby</c>.</summary>
        public string LabelId { get; }

        public int Depth { get; }

        /// <summary>True when this group's own header is expanded.</summary>
        public bool IsExpanded { get; private set; }

        /// <summary>True only when this group AND every ancestor are expanded. Items consult
        /// this (not <see cref="IsExpanded"/>) so a collapsed outer group correctly hides
        /// inner items even if the inner group is locally expanded — multi-level collapse
        /// would otherwise leak nav focus into CSS-hidden subtrees.</summary>
        public bool EffectiveIsExpanded => IsExpanded && (_parent?.EffectiveIsExpanded ?? true);

        public void SetExpanded(bool value)
        {
            if (IsExpanded == value) return;
            IsExpanded = value;
            _onChanged();
        }

        public void RegisterItem(string id, string value, bool visible, bool disabled)
        {
            // Only notify on real change — SelectItem calls this on every parameter set.
            if (_items.TryGetValue(id, out var existing)
                && existing.Value == value && existing.Visible == visible && existing.Disabled == disabled)
                return;
            _items[id] = (value, visible, disabled);
            _onChanged();
        }

        public void UnregisterItem(string id)
        {
            if (_items.Remove(id)) _onChanged();
        }

        public void RegisterChild(SelectGroupContext child)
        {
            if (!_childGroups.Contains(child)) _childGroups.Add(child);
            _onChanged();
        }

        public void UnregisterChild(SelectGroupContext child)
        {
            if (_childGroups.Remove(child)) _onChanged();
        }

        /// <summary>Triggers the owning group's change handler. Used by child groups to
        /// bubble visibility / aggregation changes up the chain.</summary>
        public void NotifyChildrenChanged() => _onChanged();

        public int VisibleDescendantCount
            => _items.Values.Count(i => i.Visible) + _childGroups.Sum(g => g.VisibleDescendantCount);

        /// <summary>Every descendant value across nested groups, excluding disabled items.
        /// Drives both the tri-state aggregation and GroupSelect's select-all toggle when
        /// no search filter is active.</summary>
        public IEnumerable<string> SelectableDescendantValues
            => _items.Values.Where(i => !i.Disabled).Select(i => i.Value)
                .Concat(_childGroups.SelectMany(g => g.SelectableDescendantValues));

        /// <summary>Selectable descendants that also currently pass the search filter. Used
        /// when a search is active so "select all" targets only matches the user can see.</summary>
        public IEnumerable<string> VisibleSelectableDescendantValues
            => _items.Values.Where(i => !i.Disabled && i.Visible).Select(i => i.Value)
                .Concat(_childGroups.SelectMany(g => g.VisibleSelectableDescendantValues));
    }
}

@namespace Lumeo
@implements IDisposable

@if (Visible)
{
    <button type="button" id="@_itemId" role="option" aria-selected="@IsSelected.ToString().ToLower()"
            aria-disabled="@Disabled.ToString().ToLower()"
            class="@CssClass" style="@IndentStyle" @onclick="HandleSelect" @attributes="AdditionalAttributes">
        <span class="flex h-3.5 w-3.5 shrink-0 items-center justify-center">
            @if (IsSelected)
