@code {
    [CascadingParameter] public Select.SelectContext Context { get; set; } = default!;
    // Present when the item sits inside one or more SelectGroups (nearest group wins).
    [CascadingParameter] public SelectGroup.SelectGroupContext? Group { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter, EditorRequired] public string Value { get; set; } = "";
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public string? Class { get; set; }
    /// <summary>Optional text used to match against the search input when Searchable is enabled. Falls back to Value.</summary>
    [Parameter] public string? SearchValue { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _itemId = LumeoIds.New("select-item");
    private bool _registered;
    private bool _groupRegistered;

    // Indent items one extra step beyond their group's header for visual nesting.
    private string IndentStyle => Group is { Depth: var d } && d >= 0
        ? $"padding-left:{0.5 + (d + 1) * 0.75:0.###}rem"
        : "";

    private bool IsSelected => Context.Multiple
        ? Context.Values != null && Context.Values.Contains(Value)
        : Context.Value == Value;

    private bool IsFocused => Context.FocusedItemId == _itemId;

    // True when the item should render as a navigable option in the listbox. A collapsed
    // ancestor group hides its items entirely (and removes them from keyboard nav), but the
    // item still registers with the group below so GroupSelect can see / mutate the
    // descendants even while collapsed.
    private bool Visible
    {
        get
        {
            // EffectiveIsExpanded (not just IsExpanded) so a collapsed outer group hides
            // inner items even when their immediate group is locally expanded.
            if (Group is { EffectiveIsExpanded: false }) return false;
            return PassesSearchFilter;
        }
    }

    // Just the search check — used to drive the group's empty-hiding and aggregate state
    // without coupling it to the collapsed/expanded view.
    private bool PassesSearchFilter
    {
        get
        {
            if (!Context.Searchable || string.IsNullOrEmpty(Context.SearchText)) return true;
            var haystack = SearchValue ?? Value;
            return haystack.Contains(Context.SearchText, StringComparison.OrdinalIgnoreCase);
        }
    }

    private string CssClass => Cx.Merge(
        "relative flex w-full select-none items-center gap-2 rounded-sm py-1.5 ps-2 pe-8 text-sm outline-none",
        Disabled ? "opacity-50 cursor-not-allowed pointer-events-none" : "cursor-pointer hover:bg-accent hover:text-accent-foreground",
        Cx.When(IsFocused && !Disabled, "bg-accent text-accent-foreground"),
        Class);

    protected override void OnParametersSet()
    {
        if (Visible)
        {
            // SearchValue (falling back to Value) is the text the search filter and
            // type-to-jump match against — keep both features consistent. Disabled
            // items register (so they still render) but are excluded from keyboard nav.
            // RegisterItem upserts, so re-calling it whenever our inputs change keeps
            // the registry in sync when Disabled/SearchValue flip while the menu is open.
            // ChildContent is ALSO registered so a Multiple-mode SelectTrigger tag can
            // re-render this item's actual label instead of echoing the raw Value (Codex P2).
            Context.RegisterItem(_itemId, Value, SearchValue ?? Value, Disabled, ChildContent);
            _registered = true;
        }
        else if (!Visible && _registered)
        {
            Context.UnregisterItem(_itemId);
            _registered = false;
        }

        // Report value + search visibility + disabled state to the enclosing group. We use
        // PassesSearchFilter (not Visible) so a collapsed group still sees its descendants for
        // GroupSelect; Disabled flows through so group-level toggles can skip non-selectable
        // items and the tri-state aggregation ignores them.
        if (Group is not null)
        {
            Group.RegisterItem(_itemId, Value, PassesSearchFilter, Disabled);
            _groupRegistered = true;
        }
    }

    public void Dispose()
    {
        if (_registered) Context.UnregisterItem(_itemId);
        if (_groupRegistered) Group?.UnregisterItem(_itemId);
    }

    private async Task HandleSelect()
    {
        if (Disabled) return;
        await Context.OnSelect.InvokeAsync(Value);
    }
}

@namespace Lumeo

<div id="@LabelId" class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [CascadingParameter] public SelectGroup.SelectGroupContext? GroupContext { get; set; }
