@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<button type="button" id="@Context.TriggerId"
        role="combobox"
        aria-haspopup="listbox"
        aria-expanded="@Context.IsOpen.ToString().ToLower()"
        aria-controls="@Context.ContentId"
        aria-activedescendant="@(Context.IsOpen ? Context.FocusedItemId : null)"
        aria-describedby="@Context.DescribedBy"
        class="@CssClass"
        disabled="@Context.Disabled"
        @onclick="Toggle"
        @onkeydown="HandleKeyDown"
        @attributes="EffectiveAttributes">
    @if (ChildContent is not null && HasValue)
    {
        @* An explicit ChildContent wins whenever there IS a value — including in
           Multiple mode. Previously the Multiple-tags branch below was checked FIRST
           and its condition (Multiple && Values.Any()) was identical to HasValue's
           Multiple case, so ChildContent could never be reached whenever Multiple=true
           and a value was selected: it wasn't overridden at runtime, it was dead code
           (Codex P2). Still gated on HasValue so the Placeholder branch below continues
           to win when nothing is selected, regardless of whether ChildContent is set. *@
        @ChildContent
    }
    else if (Context.Multiple && Context.Values != null && Context.Values.Count > 0)
    {
        <div class="flex flex-wrap gap-1 items-center flex-1 min-w-0">
            @{
                var displayed = Context.Values.Take(Context.MaxDisplayTags).ToList();
                var remaining = Context.Values.Count - Context.MaxDisplayTags;
            }
            @foreach (var val in displayed)
            {
                <span class="inline-flex items-center gap-1 rounded-md border border-border/40 bg-secondary px-1.5 py-0.5 text-xs font-medium text-secondary-foreground">
                    @* Resolve the item's actual label (composition-mode SelectItem ChildContent,
                       or ItemText/ItemValue in data-bound mode) instead of echoing the raw
                       value (e.g. a Guid) — the label is what the option itself shows when the
                       dropdown is open, so the closed trigger's tags must match (Codex P2). *@
                    @(Context.ResolveTagLabel is not null ? Context.ResolveTagLabel(val) : (RenderFragment)(b => b.AddContent(0, val)))
                    <button type="button" class="cursor-pointer rounded-[calc(var(--radius)*2)] hover:bg-foreground/20 focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1" aria-label="@($"Remove {val}")" @onclick="() => RemoveValue(val)" @onclick:stopPropagation="true">
                        <SvgGlyph Svg="@(LumeoIcons.X)" class="h-3 w-3" />
                    </button>
                </span>
            }
            @if (remaining > 0)
            {
                <span class="text-xs text-muted-foreground">+@remaining more</span>
            }
        </div>
    }
    else if (HasValue)
    {
        @* No custom ChildContent and not the Multiple-tags case (single mode with a value,
           nothing else to render here — pre-existing contract, unchanged). *@
    }
    else
    {
        <span class="text-muted-foreground">@(Placeholder ?? Context.Placeholder ?? L["Select.Placeholder"])</span>
    }

    @* self-start (not the row's default items-center) so the chevron/clear icon aligns
       with the FIRST tag row instead of being vertically centered across the full height
       once Multiple-mode tags wrap to 2+ lines — otherwise it floats mid-height "in the
       air" between rows. pt-0.5 nudges it down slightly for closer optical alignment with
       the tags' own py-0.5. A no-op in the common single-line case (self-start vs.
       items-center only differ when the row is taller than this icon strip). *@
    <div class="flex items-center gap-1 ms-auto shrink-0 self-start pt-0.5">
        @if (Context.Clearable && HasValue)
        {
            <button type="button" class="cursor-pointer hover:text-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 rounded" aria-label="@L["Select.ClearSelection"]" @onclick="HandleClear" @onclick:stopPropagation="true">
                <SvgGlyph Svg="@(LumeoIcons.X)" class="h-3.5 w-3.5 opacity-50 hover:opacity-100" />
            </button>
        }
        <SvgGlyph Svg="@(LumeoIcons.ChevronDown)" class="@($"h-4 w-4 shrink-0 opacity-50 transition-transform duration-200 {(Context.IsOpen ? "rotate-180" : "")}")" />
    </div>
</button>

@code {
    [CascadingParameter] public Select.SelectContext Context { get; set; } = default!;
    [CascadingParameter] private Lumeo.Density? Density { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Placeholder { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Inside a FormField the trigger's id is the FormField's ControlId (Context.TriggerId) and the field
    // <Label For> targets it; a consumer-splatted id renders after the explicit id= and would override it,
    // orphaning the label. Strip the id from the splat in that case (Codex P2). Outside a FormField the
    // consumer id passes through.
    private Dictionary<string, object>? EffectiveAttributes =>
        Context.InsideFormField && AdditionalAttributes?.ContainsKey("id") == true
            ? AdditionalAttributes.Where(kv => kv.Key != "id").ToDictionary(kv => kv.Key, kv => kv.Value)
            : AdditionalAttributes;

    // Height + body padding track the ambient DensityScope; Comfortable
    // reproduces the historical `h-9 px-3 py-2`.
    private string SizeClasses => Density switch
    {
        Lumeo.Density.Compact => "h-8 px-2.5 py-1.5",
        Lumeo.Density.Spacious => "h-10 px-4 py-2.5",
        _ => "h-9 px-3 py-2"
    };

    // _triggerId moved up to parent Select (Context.TriggerId) so the parent
    // can target it for AutoFocus / public FocusAsync without exposing the
    // trigger child's implementation detail.

    private bool HasValue => Context.Multiple
        ? Context.Values != null && Context.Values.Count > 0
        : !string.IsNullOrEmpty(Context.Value);

    private string CssClass => Cx.Merge("flex", SizeClasses, "w-full cursor-pointer items-center justify-between whitespace-nowrap rounded-md border", (Context.Invalid ? "border-destructive" : "border-input"), "bg-transparent text-sm placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-2", (Context.Invalid ? "focus-visible:ring-destructive/20" : "focus-visible:ring-ring"), "focus-visible:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50", Class);

    private async Task Toggle() => await Context.SetOpen.InvokeAsync(!Context.IsOpen);

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "ArrowDown":
                if (!Context.IsOpen)
                    await Context.SetOpen.InvokeAsync(true);
                else
                    await Context.SetFocusedIndex.InvokeAsync(Context.FocusedIndex + 1);
                break;
            case "ArrowUp":
                if (!Context.IsOpen)
                    await Context.SetOpen.InvokeAsync(true);
                else
                    await Context.SetFocusedIndex.InvokeAsync(Context.FocusedIndex > 0 ? Context.FocusedIndex - 1 : 0);
                break;
            case "Enter":
            case " ":
                if (!Context.IsOpen)
                    await Context.SetOpen.InvokeAsync(true);
                else if (Context.FocusedItemValue is not null)
                    await Context.OnSelect.InvokeAsync(Context.FocusedItemValue);
                break;
            case "Escape":
                await Context.SetOpen.InvokeAsync(false);
                break;
            case "Home":
                if (Context.IsOpen)
                    await Context.SetFocusedIndex.InvokeAsync(0);
                break;
            case "End":
                if (Context.IsOpen)
                    await Context.SetFocusedIndex.InvokeAsync(int.MaxValue);
                break;
        }
    }

    private async Task RemoveValue(string value)
    {
        await Context.OnSelect.InvokeAsync(value);
    }

    private async Task HandleClear()
    {
        await Context.OnClear.InvokeAsync();
    }
}
